/* ====================================================================
   PULSE — Neon Grid (synthwave)  ·  shared helpers (template base CSS)
   --------------------------------------------------------------------
   FULL-TRUST theme (allowUnsafeTemplateContent = true) → raw, unsanitized
   CSS, so @keyframes / @media survive and the signature neon glow can
   BREATHE (the pulse rules at the bottom of this file). The look still
   leans on sanitizer-safe primitives so it degrades gracefully:
     · neon glow  → box-shadow (and text-shadow)
     · grid       → repeating-linear-gradient (period baked in, no background-size)
     · accents    → rgba(var(--mud-palette-{primary,secondary,tertiary,surface}-rgb), a)
   Colors flow through the live MudBlazor palette so every surface
   auto-adapts to light / dark mode.
   ==================================================================== */

/* Wide-tracked neon wordmark (system fonts only — external fonts are stripped) */
.pl-wordmark {
    font-family: "Segoe UI", system-ui, -apple-system, Roboto, sans-serif;
    font-weight: 800;
    letter-spacing: 0.3em;
    text-transform: uppercase;
    color: var(--mud-palette-text-primary);
    text-shadow: 0 0 16px rgba(var(--mud-palette-primary-rgb), 0.7);
}
.pl-mono {
    font-family: "Cascadia Mono", "Consolas", ui-monospace, "SFMono-Regular", monospace;
    letter-spacing: 0.14em;
    font-size: 11px;
    text-transform: uppercase;
}

/* Neon logo chip — dark plate, magenta edge, layered glow, cyan glyph */
.pl-mark {
    display: inline-flex; align-items: center; justify-content: center;
    flex: none;
    border-radius: 6px;
    color: rgba(var(--mud-palette-secondary-rgb), 1);
    background: rgba(var(--mud-palette-surface-rgb), 1);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.8);
    box-shadow:
        0 0 18px -2px rgba(var(--mud-palette-primary-rgb), 0.7),
        inset 0 0 16px -4px rgba(var(--mud-palette-secondary-rgb), 0.5);
}
.pl-mark i { line-height: 1; text-shadow: 0 0 10px rgba(var(--mud-palette-secondary-rgb), 0.9); }

/* Neon status dot (fixed semantics) — glow via box-shadow */
.pl-led { width: 9px; height: 9px; border-radius: 50%; display: inline-block; flex: none; }
.pl-led--ok { background: #00ffa3; box-shadow: 0 0 0 3px rgba(0,255,163,0.18), 0 0 12px rgba(0,255,163,0.95); }

/* ---- Pulse animations (full-trust: @keyframes survive) --------------------------
   The login card's neon edge bloom and the drawer-header logo chip "breathe": the
   box-shadow eases brighter and back on a loop. Each animated rule keeps a static
   box-shadow of its own (login.css / .pl-mark) as the reduced-motion fallback. */
@keyframes pl-pulse-card {
    0%, 100% {
        box-shadow:
            0 0 0 1px rgba(var(--mud-palette-secondary-rgb), 0.22),
            0 0 32px -8px rgba(var(--mud-palette-primary-rgb), 0.42),
            0 0 58px -12px rgba(var(--mud-palette-secondary-rgb), 0.26),
            inset 0 1px 0 rgba(255,255,255,0.06);
    }
    50% {
        box-shadow:
            0 0 0 1px rgba(var(--mud-palette-secondary-rgb), 0.40),
            0 0 54px -4px rgba(var(--mud-palette-primary-rgb), 0.82),
            0 0 92px -8px rgba(var(--mud-palette-secondary-rgb), 0.54),
            inset 0 1px 0 rgba(255,255,255,0.06);
    }
}
@keyframes pl-pulse-mark {
    0%, 100% {
        box-shadow:
            0 0 13px -3px rgba(var(--mud-palette-primary-rgb), 0.50),
            inset 0 0 16px -4px rgba(var(--mud-palette-secondary-rgb), 0.50);
    }
    50% {
        box-shadow:
            0 0 27px 0 rgba(var(--mud-palette-primary-rgb), 0.95),
            inset 0 0 18px -3px rgba(var(--mud-palette-secondary-rgb), 0.68);
    }
}
@media (prefers-reduced-motion: reduce) {
    .pl-login__card, .pl-dh__mark { animation: none !important; }
}

contents.css:
/* ============ PULSE · LoginPage surface ============ */

/* Void backdrop: near-black base + a glowing neon grid + magenta/cyan horizon glows.
   The grid is repeating-linear-gradient (period baked in → no background-size, which the
   sanitizer may strip). All gradients + box-shadow survive sandboxing. */
.auth-bg-image {
    background-color: var(--mud-palette-background) !important;
    background-image:
        radial-gradient(60% 70% at 12% 4%,   rgba(var(--mud-palette-primary-rgb),   0.30), transparent 60%),
        radial-gradient(60% 70% at 90% 96%,   rgba(var(--mud-palette-secondary-rgb), 0.26), transparent 60%),
        radial-gradient(120% 60% at 50% 120%, rgba(var(--mud-palette-tertiary-rgb),  0.28), transparent 60%),
        repeating-linear-gradient(0deg,  rgba(var(--mud-palette-secondary-rgb), 0.07) 0 1px, transparent 1px 46px),
        repeating-linear-gradient(90deg, rgba(var(--mud-palette-secondary-rgb), 0.07) 0 1px, transparent 1px 46px) !important;
    background-repeat: no-repeat, no-repeat, no-repeat, repeat, repeat !important;
    background-position: center !important;
}
.auth-bg-overlay {
    background: radial-gradient(130% 110% at 50% -10%, transparent 40%, rgba(0,0,0,0.55)) !important;
    opacity: 1 !important;
}

/* Corner theme toggle → neon-edged pill */
.auth-theme-toggle .mud-icon-button {
    background: rgba(var(--mud-palette-surface-rgb), 0.8);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.5);
    border-radius: 8px;
    box-shadow: 0 0 14px -3px rgba(var(--mud-palette-primary-rgb), 0.7);
}

/* ---- Card ---- */
.pl-login { position: relative; width: 100%; display: flex; justify-content: center; }
.pl-login__announce { position: absolute; bottom: calc(100% + 18px); width: 100%; max-width: 428px; }

.pl-login__card {
    width: 428px;
    max-width: 92vw;
    padding: 40px 36px 24px;
    border-radius: 10px;
    background:
        linear-gradient(180deg, rgba(var(--mud-palette-primary-rgb), 0.08), rgba(var(--mud-palette-primary-rgb), 0) 38%),
        rgba(var(--mud-palette-surface-rgb), 0.92);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.55);
    /* layered neon edge: magenta outer bloom + cyan counter-glow + inner sheen */
    box-shadow:
        0 0 0 1px rgba(var(--mud-palette-secondary-rgb), 0.25),
        0 0 40px -6px rgba(var(--mud-palette-primary-rgb), 0.55),
        0 0 70px -10px rgba(var(--mud-palette-secondary-rgb), 0.35),
        inset 0 1px 0 rgba(255,255,255,0.06);
    /* neon edge breathes (keyframes in base.css); the box-shadow above is the reduced-motion fallback */
    animation: pl-pulse-card 3s ease-in-out infinite;
}

/* ---- Brand ---- */
.pl-login__brand { display: flex; align-items: center; gap: 16px; margin-bottom: 22px; }
.pl-login__mark { width: 56px; height: 56px; font-size: 25px; border-radius: 10px; }
.pl-login__id { display: flex; flex-direction: column; }
.pl-login__name { margin: 0; font-size: 30px; line-height: 1; }
.pl-login__tag { margin: 7px 0 0; color: rgba(var(--mud-palette-secondary-rgb), 1); text-shadow: 0 0 10px rgba(var(--mud-palette-secondary-rgb), 0.6); }

/* ---- "Jack In" divider ---- */
.pl-login__divider { display: flex; align-items: center; gap: 12px; margin: 4px 0 22px; }
.pl-login__divider-line { flex: 1; height: 1px; background: linear-gradient(90deg, transparent, rgba(var(--mud-palette-secondary-rgb), 0.6), transparent); }
.pl-login__divider-text { color: var(--mud-palette-text-secondary); }

/* ---- Form fields → dark, neon focus ---- */
.pl-login .login-field .mud-input-outlined { background: rgba(var(--mud-palette-background), 0.45); border-radius: 8px; }
.pl-login .login-field .mud-input-outlined-border {
    border-color: rgba(var(--mud-palette-secondary-rgb), 0.35);
    border-radius: 8px;
    transition: border-color .15s ease, box-shadow .15s ease;
}
.pl-login .login-field .mud-input-outlined:focus-within .mud-input-outlined-border {
    border-color: rgba(var(--mud-palette-secondary-rgb), 1) !important;
    border-width: 1px !important;
    box-shadow: 0 0 0 2px rgba(var(--mud-palette-secondary-rgb), 0.22), 0 0 18px -2px rgba(var(--mud-palette-secondary-rgb), 0.55);
}

/* ---- Submit → magenta→violet gradient, white text, neon bloom ---- */
.pl-login .login-submit-btn {
    background: linear-gradient(135deg, rgba(var(--mud-palette-primary-rgb),1) 0%, rgba(var(--mud-palette-tertiary-rgb),1) 100%) !important;
    color: #ffffff !important;
    border: 0 !important;
    border-radius: 8px;
    height: 48px;
    margin-top: 4px;
    font-weight: 800;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    box-shadow: 0 0 34px -6px rgba(var(--mud-palette-primary-rgb), 0.75);
    transition: filter .15s ease, box-shadow .2s ease, transform .1s ease;
}
.pl-login .login-submit-btn:hover { filter: brightness(1.1); box-shadow: 0 0 46px -4px rgba(var(--mud-palette-primary-rgb), 0.9); }
.pl-login .login-submit-btn:active { transform: translateY(1px); }
.pl-login .login-forgot-btn { font-size: 12px; color: rgba(var(--mud-palette-secondary-rgb), 1); }

/* ---- Footer row ---- */
.pl-login__foot {
    display: flex; align-items: center; gap: 9px;
    margin-top: 20px; padding-top: 16px;
    border-top: 1px solid rgba(var(--mud-palette-primary-rgb), 0.25);
}
.pl-login__foot-text { color: var(--mud-palette-text-secondary); }
.pl-login__lang { margin-left: auto; }
.pl-login__lang .mud-input-control { margin: 0; }

.auth-footer { color: var(--mud-palette-text-secondary); opacity: 0.7; letter-spacing: 0.08em; }

/* ============ PULSE · Shell surface (authenticated chrome) ============
   Composed {% component "shell" %} so MudBlazor owns layout coordination
   (no drawer-pin needed). Scoped via :has(.mud-appbar) so none of it leaks
   onto the login page. SANDBOXED → glow = box-shadow, grid =
   repeating-linear-gradient, no clip-path / keyframes / backdrop-filter. */

/* ---- Void deck + glowing neon grid ---- */
.mud-layout:has(.mud-appbar) {
    background-color: var(--mud-palette-background) !important;
    background-image:
        radial-gradient(46% 56% at 6% 0%,    rgba(var(--mud-palette-primary-rgb),   0.20), transparent 60%),
        radial-gradient(44% 60% at 99% 3%,    rgba(var(--mud-palette-secondary-rgb), 0.16), transparent 58%),
        radial-gradient(80% 50% at 50% 118%,  rgba(var(--mud-palette-tertiary-rgb),  0.18), transparent 60%),
        repeating-linear-gradient(0deg,  rgba(var(--mud-palette-secondary-rgb), 0.05) 0 1px, transparent 1px 48px),
        repeating-linear-gradient(90deg, rgba(var(--mud-palette-secondary-rgb), 0.05) 0 1px, transparent 1px 48px) !important;
    background-attachment: fixed, fixed, fixed, fixed, fixed !important;
    background-repeat: no-repeat, no-repeat, no-repeat, repeat, repeat !important;
}
/* Transparent so the neon-grid backdrop shows through. isolation:isolate makes
   this a stacking context so the game-service hero's z-index:-10 background
   image stays contained ABOVE this opaque backdrop — without it the negative
   z-index escapes to the root stacking context and the .mud-layout
   background-color paints over the image (it only "worked" on the default
   theme because that layout is transparent). */
.mud-layout:has(.mud-appbar) .mud-main-content { background: transparent !important; isolation: isolate; }

/* ---- Top app bar → dark, cyan underglow ---- */
.mud-layout:has(.mud-appbar) .mud-appbar {
    background: rgba(var(--mud-palette-surface-rgb), 0.82) !important;
    border-bottom: 1px solid rgba(var(--mud-palette-secondary-rgb), 0.45);
    box-shadow: 0 0 26px -6px rgba(var(--mud-palette-secondary-rgb), 0.5);
}

/* ---- Navigation drawer → dark, magenta right edge glow ---- */
.mud-layout:has(.mud-appbar) .mud-drawer {
    background: rgba(var(--mud-palette-surface-rgb), 0.9) !important;
    border-right: 1px solid rgba(var(--mud-palette-primary-rgb), 0.4);
    box-shadow: inset -1px 0 18px -8px rgba(var(--mud-palette-primary-rgb), 0.6);
}
.mud-layout:has(.mud-appbar) .mud-drawer-content { overflow-x: hidden; }

/* ---- Nav links: cyan hover, magenta glowing rail on active ---- */
.mud-layout:has(.mud-appbar) .mud-nav-link {
    border-radius: 7px;
    margin: 2px 8px;
    transition: background-color .15s ease, color .15s ease, box-shadow .15s ease;
}
.mud-layout:has(.mud-appbar) .mud-nav-link:hover { background: rgba(var(--mud-palette-secondary-rgb), 0.10); }
.mud-layout:has(.mud-appbar) .mud-nav-link.active {
    background: rgba(var(--mud-palette-primary-rgb), 0.14);
    color: rgba(var(--mud-palette-primary-rgb), 1) !important;
    box-shadow: inset 3px 0 0 0 rgba(var(--mud-palette-primary-rgb), 1), 0 0 20px -6px rgba(var(--mud-palette-primary-rgb), 0.6);
}
.mud-layout:has(.mud-appbar) .mud-nav-link.active .mud-nav-link-icon { color: rgba(var(--mud-palette-primary-rgb), 1) !important; }

/* Collapsed (mini) rail: the expanded h-margin shifts the icon right and the drawer's
   overflow-x:hidden clips it — drop it in the closed state so the icon re-centers in the rail. */
.mud-layout:has(.mud-appbar) .mud-drawer--closed .mud-nav-link { margin-left: 0; margin-right: 0; }

/* ---- Content cards → dark plates with a neon edge glow (scoped to main content so
   dialogs / popovers / menus, which render in a portal, stay opaque) ----
   :not([style*="background-image"]) skips papers that set their own inline
   background image (the game/service hero, list-row + grid cards) — otherwise
   this !important background shorthand overpaints their url with the plate. */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-paper:not(.mud-table-container):not(.mud-menu-list):not(.mud-list):not([style*="background-image"]) {
    background:
        linear-gradient(180deg, rgba(var(--mud-palette-primary-rgb), 0.05), rgba(var(--mud-palette-primary-rgb), 0) 40%),
        rgba(var(--mud-palette-surface-rgb), 0.88) !important;
    border: 1px solid rgba(var(--mud-palette-secondary-rgb), 0.22);
    border-radius: 10px !important;
    box-shadow: 0 0 0 1px rgba(var(--mud-palette-primary-rgb), 0.06), 0 18px 44px -24px rgba(var(--mud-palette-primary-rgb), 0.5);
}
/* Inner nested papers stay flat (no double tint / glow) — but never blank out
   a nested card that carries its own inline background image (e.g. the grid /
   list game cards live inside an outer paper). */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-paper .mud-paper:not([style*="background-image"]) {
    background: transparent !important;
    box-shadow: none;
    border: 0;
}

/* ---- In-app primary buttons → magenta→violet gradient + bloom ---- */
.mud-layout:has(.mud-appbar) .mud-main-content .mud-button-filled-primary {
    background: linear-gradient(135deg, rgba(var(--mud-palette-primary-rgb),1) 0%, rgba(var(--mud-palette-tertiary-rgb),1) 100%) !important;
    color: #ffffff !important;
    border: 0 !important;
    box-shadow: 0 0 30px -8px rgba(var(--mud-palette-primary-rgb), 0.7);
}

/* ============ PULSE · Shell.DrawerFooter (account block + our own logout) ============ */

/* Hide the compiled drawer's default Profile + Logout block — we render our own, on-brand. */
.mud-drawer .mud-navmenu.mt-auto { display: none; }

.pl-df {
    display: flex; flex-direction: column; gap: 4px;
    margin: auto 12px 14px;            /* margin-top:auto pins the block to the drawer bottom */
    padding: 6px;
    border-radius: 12px;
    background: rgba(var(--mud-palette-primary-rgb), 0.10);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.4);
    box-shadow: 0 0 22px -10px rgba(var(--mud-palette-primary-rgb), 0.6);
}

.pl-df__user {
    display: flex; align-items: center; gap: 11px;
    padding: 7px 8px; border-radius: 9px;
    text-decoration: none; color: inherit;
    transition: background-color .15s ease;
}
.pl-df__user:hover { background: rgba(var(--mud-palette-primary-rgb), 0.14); }
.pl-df__avatar {
    width: 34px; height: 34px; flex: none;
    display: inline-flex; align-items: center; justify-content: center;
    border-radius: 9px;
    background: rgba(var(--mud-palette-surface-rgb), 1);
    border: 1px solid rgba(var(--mud-palette-secondary-rgb), 0.6);
    color: rgba(var(--mud-palette-secondary-rgb), 1);
    font-size: 15px;
    box-shadow: inset 0 0 12px -4px rgba(var(--mud-palette-secondary-rgb), 0.7);
}
.pl-df__meta { display: flex; flex-direction: column; min-width: 0; overflow: hidden; }
.pl-df__name {
    font-size: 13px; font-weight: 700;
    color: var(--mud-palette-text-primary);
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.pl-df__role { margin-top: 1px; color: var(--mud-palette-text-secondary); font-size: 10px; }
.pl-df__led { margin-left: auto; }

.pl-df__logout {
    display: flex; align-items: center; gap: 11px;
    padding: 8px; border-radius: 9px;
    text-decoration: none;
    color: var(--mud-palette-text-secondary);
    font-size: 13px; font-weight: 600;
    transition: background-color .15s ease, color .15s ease;
}
.pl-df__logout:hover { background: rgba(255,61,110,0.14); color: #ff3d6e; }
.pl-df__logout-ico { width: 34px; flex: none; text-align: center; font-size: 15px; }

/* Collapsed (mini) drawer → icons only, centered */
.mud-drawer--closed .pl-df { margin: auto 6px 12px; padding: 6px; background: transparent; border: 0; box-shadow: none; }
.mud-drawer--closed .pl-df__user { justify-content: center; padding: 6px; }
.mud-drawer--closed .pl-df__logout { justify-content: center; padding: 6px; }
.mud-drawer--closed .pl-df__logout-ico { width: auto; }
.mud-drawer--closed .pl-df__meta,
.mud-drawer--closed .pl-df__led,
.mud-drawer--closed .pl-df__logout-text { display: none; }

/* ============ PULSE · Shell.DrawerHeader (brand zone, above the nav) ============ */
.pl-dh { display: flex; align-items: center; gap: 13px; padding: 18px 16px 14px; }
.pl-dh__mark { width: 40px; height: 40px; font-size: 18px; border-radius: 8px; animation: pl-pulse-mark 2.6s ease-in-out infinite; }
.pl-dh__text { display: flex; flex-direction: column; min-width: 0; overflow: hidden; white-space: nowrap; }
.pl-dh__name { font-size: 18px; line-height: 1; letter-spacing: 0.26em; }
.pl-dh__tag { margin-top: 4px; color: rgba(var(--mud-palette-secondary-rgb), 1); text-shadow: 0 0 9px rgba(var(--mud-palette-secondary-rgb), 0.6); }

/* Collapsed (mini) drawer → chip only, centered */
.mud-drawer--closed .pl-dh { justify-content: center; padding-left: 0; padding-right: 0; }
.mud-drawer--closed .pl-dh__text { display: none; }

/* ============ PULSE · Shell.Footer (scanline status bar) ============ */
.pl-ft {
    display: flex; align-items: center; gap: 10px;
    width: 100%; padding: 0 14px;
    font-size: 12px; color: var(--mud-palette-text-secondary);
    border-top: 1px solid rgba(var(--mud-palette-primary-rgb), 0.3);
    /* faint CRT scanlines — repeating-linear-gradient survives sandboxing */
    background-image: repeating-linear-gradient(0deg, rgba(var(--mud-palette-secondary-rgb), 0.045) 0 1px, transparent 1px 3px);
}
.pl-ft__brand { display: inline-flex; align-items: center; gap: 8px; flex: none; }
.pl-ft__wave { color: rgba(var(--mud-palette-secondary-rgb), 1); font-size: 12px; text-shadow: 0 0 8px rgba(var(--mud-palette-secondary-rgb), 0.8); }
.pl-ft__name { font-size: 11px; letter-spacing: 0.24em; }

/* Page-driven live service stats fill the middle; the section's own MudSpacer right-aligns its status. */
.pl-ft__resources { flex: 1; display: flex; align-items: center; min-width: 0; overflow: hidden; }

.pl-ft__item { display: inline-flex; align-items: center; gap: 6px; flex: none; }
.pl-ft__ver {
    color: rgba(var(--mud-palette-secondary-rgb), 1);
    padding: 2px 9px; border-radius: 999px;
    background: rgba(var(--mud-palette-secondary-rgb), 0.12);
    border: 1px solid rgba(var(--mud-palette-secondary-rgb), 0.3);
}

/* ============ PULSE · Shell.MenuLinks (custom links appended to the nav) ============ */
/* The .mud-nav-link anchor inherits native nav styling + the Shell surface's
   neon hover/active rules. Only the FA icon needs sizing to match MudBlazor's 24px
   nav icons; mud-icon-root is load-bearing for the mini-collapse rail. */
.pl-ml-ico { font-size: 24px; width: 24px; text-align: center; }

/* ============ PULSE · Shell.TopBarEnd (SYS health + live pill, after the dark-mode toggle) ============ */
.pl-te { display: inline-flex; align-items: center; gap: 10px; margin-left: 8px; margin-right: 4px; }

/* System-health chip — sits bare beside the LIVE pill (it is its own colored status pill). A cyan neon
   halo ties it to the synthwave palette (box-shadow survives the sandbox); drop the component's baked-in
   `margin-left:8px` so the flex gap owns the spacing. It self-gates on SystemHealth.View, so `:has()`
   collapses the empty wrapper for users without the permission (no stray gap before the LIVE pill). */
.pl-te__health { display: inline-flex; align-items: center; }
.pl-te__health:not(:has(.mud-chip)) { display: none; }
.pl-te__health .mud-chip { margin-left: 0 !important; box-shadow: 0 0 14px -4px rgba(var(--mud-palette-secondary-rgb), 0.55); }

.pl-te__pill {
    display: inline-flex; align-items: center; gap: 8px;
    padding: 4px 11px; border-radius: 999px;
    background: rgba(var(--mud-palette-surface-rgb), 0.7);
    border: 1px solid rgba(var(--mud-palette-secondary-rgb), 0.45);
    box-shadow: 0 0 16px -5px rgba(var(--mud-palette-secondary-rgb), 0.6);
}
.pl-te__label { color: rgba(var(--mud-palette-secondary-rgb), 1); }
.pl-te__indicator { display: inline-flex; align-items: center; }
/* The connection dot rides 3px high otherwise: MudTooltip's root is display:block, so its inline-flex
   icon activator baseline-aligns in a taller line-box. Flex-center the root + kill the line-box. */
.pl-te__indicator .mud-tooltip-root { display: flex; align-items: center; line-height: 0; }
